<?php namespace App\Http\Controllers\Api\V1; use App\Http\Controllers\Controller; use App\Services\BackupService; use App\Traits\ApiResponseTrait; use Illuminate\Http\Request; use Illuminate\Http\JsonResponse; class BackupController extends Controller { use ApiResponseTrait; protected BackupService $backupService; public function __construct(BackupService $backupService) { $this->middleware(['auth', 'admin']); $this->backupService = $backupService; } public function index(): JsonResponse { $backups = $this->backupService->listBackups(); return $this->successResponse($backups, 'تم استعراض قائمة النسخ الاحتياطية بنجاح.'); } public function store(): JsonResponse { $result = $this->backupService->createBackup(); if (!$result) { return $this->errorResponse('فشل في إنشاء النسخة الاحتياطية.', 500); } return $this->successResponse(null, 'تم إنشاء النسخة الاحتياطية بنجاح.'); } public function download(string $fileName): JsonResponse|\Symfony\Component\HttpFoundation\BinaryFileResponse { $file = $this->backupService->getBackupPath($fileName); if (!file_exists($file)) { return $this->errorResponse('الملف غير موجود.', 404); } return response()->download($file); } public function destroy(string $fileName): JsonResponse { $deleted = $this->backupService->deleteBackup($fileName); if (!$deleted) { return $this->errorResponse('تعذر حذف الملف أو أنه غير موجود.', 404); } return $this->successResponse(null, 'تم حذف النسخة الاحتياطية بنجاح.'); } }